async function checkAccess(){const e=document.getElementById("admin-pass").value,t=document.getElementById("login-error");try{if(await hashString(e)==="4de9a48824f9ca72125798e7eca051baf13c3e3a403d7fdcf0662f4844fd28ea"){document.getElementById("login-section").style.display="none",document.getElementById("stats-content").style.display="block",loadStats()}else t.style.display="block",t.innerText="Incorrect Password"}catch(n){t.style.display="block",t.innerText="Security error."}}async function hashString(e){const t=(new TextEncoder).encode(e),n=await crypto.subtle.digest("SHA-256",t);return Array.from(new Uint8Array(n)).map(e=>e.toString(16).padStart(2,"0")).join("")}async function loadStats(){const e=document.getElementById("visit-count"),t=document.getElementById("questions-count"),n=document.getElementById("raw-json");if(e&&t&&n){e.innerText="Loading...",t.innerText="Loading...",n.value="Initiating request...";try{const s=encodeURIComponent("https://api.counterapi.dev/v1/josemanuel31675-cv/visits"),a=encodeURIComponent("https://api.counterapi.dev/v1/josemanuel31675-cv/questions"),[r,c]=await Promise.all([fetch(`https://corsproxy.io/?${s}`),fetch(`https://corsproxy.io/?${a}`)]);if(r.ok&&c.ok){const s=await r.json(),a=await c.json();e.innerText=s.count,t.innerText=a.count,n.value=`Visits API:\n${JSON.stringify(s,null,2)}\n\nQuestions API:\n${JSON.stringify(a,null,2)}`;return}}catch(s){}e.innerText="Error",t.innerText="Error"}}
